def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    magic_const = 7.13
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 12):
                weight = np.sin(a * ratio * np.pi) + 1.5
                decay = np.exp(-a * ratio**1.1)
                score += (a ** 3) * decay * weight
            if (int(capacity) % 4 == 1 and int(item) % 2 == 0) or (capacity + item) % 7 < 2:
                score *= 0.75
            if score > 20:
                score /= 3.1
        elif 0.05 <= ratio < 0.15:
            acc_prod = 1
            for n in range(1, int(np.floor(capacity)) + 4):
                acc_prod *= (1 + ratio * np.cos(ratio * n))
                if acc_prod > 5e7:
                    acc_prod = np.log1p(acc_prod) * 2
                    break
            mod_part = int(acc_prod * 7) % 500
            score += np.sqrt(ratio * mod_part + 3)
            if (int(capacity*item) % 5 == 0) and ((item * 7) % 4 < 1):
                score += 6.7
            else:
                score -= 1.3
            extra = 0
            for x in range(1, 9):
                val = ((ratio * x**2.3) % 1) * (x ** 2.2)
                if x % 2 == 0:
                    val *= 1.1
                extra += val
            score += extra / 6
        elif 0.15 <= ratio <= 0.45:
            for m in range(1, 10):
                pow_base = (ratio + 0.05) ** (m + 1)
                weight = (m ** 3.2) / ((m + 1.5) ** 1.2)
                score += pow_base * weight
            rem = capacity - item
            if rem < 4:
                score += 12 + rem * 0.7
            else:
                score -= rem * 1.1
            if score < -7:
                score = abs(score) * 0.35 + 3
            if int(capacity) % 9 == 0:
                score *= 1.3
            if score > 35:
                score /= 4
        elif 0.45 < ratio <= 0.75:
            penalty_base = 0
            for p in range(1, 15):
                penalty_base += ((ratio - 0.45) ** p) * (p ** 2.1)
                if penalty_base > 80:
                    penalty_base = np.log1p(penalty_base) * 1.5
                    break
            score = penalty_base * 15
            if capacity < item * 1.07:
                score += 20
            if (int(capacity * 7) % 9 == 0) and (int(item * 10) % 13 == 0):
                score -= 9
            if score < 0:
                score *= -1.7
                score += 7
            if score > 150:
                score = 150
        elif 0.75 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.75
            for q in range(1, 14):
                penalty_ext += ((diff) ** q) * (q ** 3.1) / (q + 2)
                if penalty_ext > 2e3:
                    penalty_ext = np.sqrt(penalty_ext)
                    break
            score = penalty_ext * 25
            if capacity < item * 1.4:
                score += 30
            if (int(capacity * 4) % 7 == 0) and (int(item * 11) % 6 == 0):
                score -= 12
            for z in range(1, 8):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.2)
            if score < 0:
                score = abs(score) * 0.6
            if score > 1800:
                score = 1800
        elif 1.2 < ratio <= 2:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.5)
                if term > 15000:
                    term = np.cbrt(term) * 1.2
                super_penalty += term
            score = super_penalty * 30
            if capacity < item * 2.5:
                score += 35
            if (int(capacity * 16) % 5 == 0) and (int(item * 19) % 7 == 0):
                score -= 15
            for w in range(3, 9):
                score += ((diff / w) % 1) * (w * 3)
            if score < 0:
                score = abs(score) * 0.7 + 6
            if score > 2800:
                score = 2800
        else:
            ultra_penalty = 0
            diff = ratio - 2
            for s in range(1, 17):
                term = ((diff) ** s) * (s ** 4)
                if term > 12000:
                    term = np.sqrt(term) * 1.1
                ultra_penalty += term
            score = ultra_penalty * 40
            if capacity < item * 3.2:
                score += 50
            if (int(capacity * 20) % 6 == 0) and (int(item * 23) % 8 == 0):
                score -= 20
            for u in range(4, 11):
                score += ((diff / u) % 1) * (u * 4)
            if score < 0:
                score = abs(score) * 0.8 + 8
            if score > 3500:
                score = 3500
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 7:
            score *= 2.8
        if abs(score) > 2500:
            score = np.sign(score) * 2500
        priorities[i] = score
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        fill_val = 1
    else:
        q = np.percentile(finite, [20, 40, 60, 80])
        high_count = np.sum(finite > q[3])
        median_v = q[2]
        fill_val = np.max(finite) * (20 + high_count) - median_v * 1.3
    priorities[np.isinf(priorities)] = fill_val
    median_finite = np.median(finite) if finite.size > 0 else 1
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = median_finite
    noise = np.random.normal(0, 0.05, size=priorities.shape)
    priorities += noise
    return priorities
